 389 |                 // --- SMART SENTENCE LOGIC (PASS-THROUGH) ---
 390 |                 // We expose this function so the parent component can call it 
 391 |                 // even though the iframe has pointer-events: none
 392 |                 const win = iframe.contentWindow;
 393 |                 
 394 |                 win.highlightAt = (clientX, clientY) => {
 395 |                     if (!win.CSS || !win.CSS.highlights) return false;
 396 | 
 397 |                     let range;
 398 |                     if (doc.caretRangeFromPoint) {
 399 |                         range = doc.caretRangeFromPoint(clientX, clientY);
 400 |                     } else if (doc.caretPositionFromPoint) {
 401 |                         const pos = doc.caretPositionFromPoint(clientX, clientY);
 402 |                         range = doc.createRange();
 403 |                         range.setStart(pos.offsetNode, pos.offset);
 404 |                         range.collapse(true);
 405 |                     }
 406 | 
 407 |                     // Rule 1: Prevent interaction with Question Cards
 408 |                     const targetNode = range?.startContainer;
 409 |                     const targetElement = targetNode?.nodeType === 3 ? targetNode.parentElement : targetNode;
 410 |                     if (targetElement?.closest('.miron-portal-container')) {
 411 |                         win.CSS.highlights.clear();
 412 |                         return false;
 413 |                     }
 414 | 
 415 |                     // Check if we hit valid text content
 416 |                     if (!range || !docBody.contains(targetNode)) {
 417 |                         win.CSS.highlights.clear();
 418 |                         return false;
 419 |                     }
 420 |                     if (targetNode.nodeType !== 3) {
 421 |                         win.CSS.highlights.clear();
 422 |                         return false;
 423 |                     }
 424 | 
 425 |                     // Rule 2: Bound to Page (Find closest container that is NOT the body)
 426 |                     const pageBoundary = targetElement.closest('.page, .page-container, .text-container') || docBody;
 427 | 
 428 |                     const sentenceRange = findSentenceRange(doc, targetNode, range.startOffset, pageBoundary);
 429 |                     if (sentenceRange) {
 430 |                         // Apply Highlight
 431 |                         const highlight = new win.Highlight(sentenceRange);
 432 |                         win.CSS.highlights.set("sentence-focus", highlight);
 433 |                         
 434 |                         // Return Metadata for Context Menu
 435 |                         const rect = sentenceRange.getBoundingClientRect();
 436 |                         return {
 437 |                             found: true,
 438 |                             text: sentenceRange.toString(),
 439 |                             rect: { x: rect.x, y: rect.y, width: rect.width, height: rect.height }
 440 |                         };
 441 |                     }
 442 |                     
 443 |                     win.CSS.highlights.clear();
 444 |                     return { found: false };
 445 |                 };
 446 | 
 447 |                 function findSentenceRange(rootDoc, startNode, startOffset, pageBoundary) {
 448 |                     const sentenceEndRegex = /[.!?]/;
 449 |                     
 450 |                     // Helper: TreeWalker for linear text traversal within the page
 451 |                     function createWalker(root) {
 452 |                         return rootDoc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
 453 |                     }
 454 | 
 455 |                     // 1. BACKWARD SCAN (Find start)
 456 |                     let currentStartNode = startNode;
 457 |                     let currentStartOffset = startOffset;
 458 |                     let finalStartNode = startNode;
 459 |                     let finalStartOffset = 0;
 460 | 
 461 |                     let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
 462 |                     let lastPuncIndex = -1;
 463 |                     for(let i = textBefore.length - 1; i >= 0; i--) {
 464 |                         if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
 465 |                     }
 466 | 
 467 |                     if (lastPuncIndex !== -1) {
 468 |                         finalStartOffset = lastPuncIndex + 1;
 469 |                         if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 470 |                     } else {
 471 |                         const walker = createWalker(pageBoundary);
 472 |                         walker.currentNode = currentStartNode;
 473 |                         let prevNode = walker.previousNode();
 474 |                         let foundStart = false;
 475 | 
 476 |                         while (prevNode && !foundStart) {
 477 |                             const text = prevNode.textContent;
 478 |                             for (let i = text.length - 1; i >= 0; i--) {
 479 |                                 if (sentenceEndRegex.test(text[i])) {
 480 |                                     finalStartNode = prevNode; finalStartOffset = i + 1;
 481 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
 482 |                                     foundStart = true; break;
 483 |                                 }
 484 |                             }
 485 |                             if (!foundStart) {
 486 |                                 finalStartNode = prevNode; finalStartOffset = 0;
 487 |                                 prevNode = walker.previousNode();
 488 |                             }
 489 |                         }
 490 |                     }
 491 | 
 492 |                     // 2. FORWARD SCAN (Find end)
 493 |                     let currentEndNode = startNode;
 494 |                     let currentEndOffset = startOffset;
 495 |                     let finalEndNode = startNode;
 496 |                     let finalEndOffset = startNode.textContent.length;
 497 | 
 498 |                     let textAfter = currentEndNode.textContent.substring(currentEndOffset);
 499 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
 500 | 
 501 |                     if (nextPuncIndex !== -1) {
 502 |                         finalEndOffset = currentEndOffset + nextPuncIndex + 1;
 503 |                     } else {
 504 |                         const walker = createWalker(pageBoundary);
 505 |                         walker.currentNode = currentEndNode;
 506 |                         let nextNode = walker.nextNode();
 507 |                         let foundEnd = false;
 508 | 
 509 |                         while (nextNode && !foundEnd) {
 510 |                             const text = nextNode.textContent;
 511 |                             const puncIdx = text.search(sentenceEndRegex);
 512 |                             if (puncIdx !== -1) {
 513 |                                 finalEndNode = nextNode; finalEndOffset = puncIdx + 1;
 514 |                                 foundEnd = true;
 515 |                             } else {
 516 |                                 finalEndNode = nextNode; finalEndOffset = text.length;
 517 |                                 nextNode = walker.nextNode();
 518 |                             }
 519 |                         }
 520 |                     }
 521 | 
 522 |                     // Create the final Range
 523 |                     const r = rootDoc.createRange();
 524 |                     try {
 525 |                         r.setStart(finalStartNode, finalStartOffset);
 526 |                         r.setEnd(finalEndNode, finalEndOffset);
 527 |                         return r;
 528 |                     } catch (e) {
 529 |                         console.warn("Sentence Range Error:", e);
 530 |                         return null;
 531 |                     }
 532 |                 }
 533 |             } catch (err) {
 534 |                 console.error("Iframe Load Error:", err);
 535 |             }
