 555 | 
 556 |     const handleFitPage = () => {
 557 |         // Reset Zoom to Width Fit
 558 |         const currentRealY = state.current.y / state.current.scale;
 559 |         state.current.scale = minScaleLimit.current;
 560 |         state.current.x = 0;
 561 |         state.current.y = currentRealY * state.current.scale; // Maintain relative Y position
 562 |         velocity.current = { x: 0, y: 0 };
 563 |         setIsFabActive(false);
 564 |     };
 565 | 
 566 |     // --- OPTIMIZED PHYSICS ENGINE ---
 567 | 
 568 |     const applyConstraints = () => {
 569 |         const vw = window.innerWidth;
 570 |         const vh = window.innerHeight;
 571 |         const { width, height } = contentDims.current;
 572 |         const s = state.current;
 573 |         const v = velocity.current;
 574 |         
 575 |         const visualW = width * s.scale;
 576 |         const visualH = height * s.scale;
 577 | 
 578 |         // X Constraint
 579 |         if (visualW < vw) {
 580 |             s.x = (vw - visualW) / 2;
 581 |             v.x = 0;
 582 |         } else {
 583 |             if (s.x > 0) { s.x = 0; v.x = 0; }
 584 |             if (s.x < vw - visualW) { s.x = vw - visualW; v.x = 0; }
 585 |         }
 586 | 
 587 |         // Y Constraint
 588 |         if (visualH < vh) {
 589 |             s.y = (vh - visualH) / 2;
 590 |             v.y = 0;
 591 |         } else {
 592 |             if (s.y > 0) { s.y = 0; v.y = 0; }
 593 |             if (s.y < vh - visualH) { s.y = vh - visualH; v.y = 0; }
 594 |         }
 595 |     };
