 597 |     // The Single Render Loop
 598 |     // Decouples input frequency from screen refresh rate for buttery smooth motion
 599 |     const loop = () => {
 600 |         // 1. Apply Physics if not dragging
 601 |         if (!input.current.isDragging) {
 602 |             const v = velocity.current;
 603 |             // Apply snap-stop: if velocity is low, kill it immediately
 604 |             if (Math.abs(v.x) < 0.5) v.x = 0;
 605 |             if (Math.abs(v.y) < 0.5) v.y = 0;
 606 | 
 607 |             if (v.x !== 0 || v.y !== 0) {
 608 |                 v.x *= CONFIG.friction;
 609 |                 v.y *= CONFIG.friction;
 610 |                 state.current.x += v.x;
 611 |                 state.current.y += v.y;
 612 |             }
 613 |         }
 614 | 
 615 |         // 2. Apply Constraints (Borders)
 616 |         applyConstraints();
 617 | 
 618 |         // 3. Render to DOM
 619 |         if (layerRef.current) {
 620 |             const { x, y, scale } = state.current;
 621 |             // Using transform3d for hardware acceleration
 622 |             layerRef.current.style.transform = `translate3d(${x}px, ${y}px, 0) scale(${scale})`;
 623 |         }
 624 | 
 625 |         // 4. Update UI (Slider & Pages)
 626 |         if (sliderRef.current && pageCountRef.current && contentDims.current.height > 0) {
 627 |             // Use Unscaled values for stability across Zoom levels
 628 |             const unscaledTotalH = contentDims.current.height;
 629 |             const unscaledY = Math.abs(state.current.y) / state.current.scale;
 630 |             const viewHeight = window.innerHeight / state.current.scale;
 631 |             
 632 |             // Slider Progress (0-100%)
 633 |             // We compare unscaled position against the maximum possible unscaled scroll
 634 |             const maxScroll = Math.max(1, unscaledTotalH - viewHeight);
 635 |             
 636 |             if (!input.current.isSliderDragging) {
 637 |                 const progress = (unscaledY / maxScroll) * 100;
 638 |                 sliderRef.current.value = Math.max(0, Math.min(100, progress));
 639 |             }
 640 | 
 641 |             // Page Count Logic (Standard Book Ratio 1.3)
 642 |             // This calculates pages based on content dimensions (like an ebook), not screen height.
 643 |             // It ensures the count is stable (doesn't change with zoom) and more accurate (higher count on mobile).
 644 |             const bookPageHeight = contentDims.current.width * 1.3;
 645 |             const totalPages = Math.max(1, Math.ceil(unscaledTotalH / bookPageHeight));
 646 |             
 647 |             // Calculate current page based on the top visible edge
 648 |             const currentPage = Math.min(totalPages, Math.max(1, Math.floor((unscaledY + (bookPageHeight * 0.3)) / bookPageHeight) + 1));
 649 |             
 650 |             pageCountRef.current.innerText = `${currentPage}/${totalPages}`;
 651 |         }
 652 | 
 653 |         // 5. Continue Loop
 654 |         requestRef.current = requestAnimationFrame(loop);
