    width: 100%;
    padding: 0.8em;
    background: var(--accent-teal);
    color: #0c0c0c;
    font-weight: 700;
    font-size: 1em;
    border: none;
    border-radius: 0.7em;
    cursor: pointer;
}

/* Navigation Controls */
.q-nav-footer {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: 1.2em;
    padding-top: 1em;
    border-top: 1px solid rgba(255,255,255,0.05);
}

.q-nav-btn {
    background: rgba(255,255,255,0.05);
    color: #999;
    border: none;
    padding: 0.5em 1em;
    border-radius: 0.5em;
    font-size: 0.8em;
    cursor: pointer;
}

.q-nav-info {
    font-size: 0.8em;
    color: #666;
    font-weight: 500;
}

operations.find_block:
contentDims.current = { width: w, height: h };

const mironCount = doc.querySelectorAll('.miron-question-card').length;
console.log(`[IFRAME] Dimensions: ${w}x${h}. Miron Challenges detected: ${mironCount}`);

operations.replace_with:
contentDims.current = { width: w, height: h };

// --- INJECT NAVIGATION LOGIC ---
const questions = doc.querySelectorAll('.miron-question-card');
if (questions.length > 0) {
    questions[0].classList.add('active');

    questions.forEach((card, index) => {
        const footer = doc.createElement('div');
        footer.className = 'q-nav-footer';

        const info = doc.createElement('span');
        info.className = 'q-nav-info';
        info.innerText = `Challenge ${index + 1} of ${questions.length}`;

        const nextBtn = doc.createElement('button');
        nextBtn.className = 'q-nav-btn';
        nextBtn.innerText = index === questions.length - 1 ? 'Back to First' : 'Next Challenge';

        nextBtn.onclick = () => {
            card.classList.remove('active');
            const nextIndex = (index + 1) % questions.length;
            questions[nextIndex].classList.add('active');
        };

        footer.appendChild(info);
        footer.appendChild(nextBtn);
        card.appendChild(footer);
    });
}

console.log(`[IFRAME] Dimensions: ${w}x${h}. Miron Challenges detected: ${questions.length}`);
